'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Settings, User, Lock, Cpu, Trash2, Check, Menu, Eye, EyeOff } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import { createClient } from '@/utils/supabase/client';
import { SidebarNavigation } from '@/components/ui/SidebarNavigation';
import toast from 'react-hot-toast';

const MODELS = [
  { key: 'auto',        label: 'Auto (Best available)',         desc: 'Tries Groq ΓåÆ HuggingFace ΓåÆ OpenRouter' },
  { key: 'groq',        label: 'Groq ΓÇö Llama 3.3 70B',         desc: 'Fast and capable' },
  { key: 'huggingface', label: 'HuggingFace ΓÇö Llama 3.1 8B',   desc: 'Free ┬╖ No quota limits' },
  { key: 'openrouter',  label: 'OpenRouter ΓÇö Free models',      desc: 'Community free tier' },
  { key: 'image',       label: 'Image Gen ΓÇö Pollinations AI',   desc: 'Text-to-image ┬╖ Free' },
];

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }}
      className="bg-white rounded-2xl border border-black/5 shadow-sm overflow-hidden"
    >
      <div className="px-6 py-4 border-b border-black/5">
        <h3 className="font-semibold text-slate-900 text-[15px]">{title}</h3>
      </div>
      <div className="px-6 py-5">{children}</div>
    </motion.div>
  );
}

export default function SettingsPage() {
  const router = useRouter();
  const { user, signOut, displayName } = useAuth();
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const supabase = createClient();

  // Profile
  const [name, setName] = useState('');
  const [savingName, setSavingName] = useState(false);

  // Password
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [savingPw, setSavingPw] = useState(false);

  // Default model
  const [defaultModel, setDefaultModel] = useState('auto');

  // Delete confirm
  const [deleteConfirm, setDeleteConfirm] = useState(false);

  useEffect(() => {
    if (user) {
      const savedName = (user.user_metadata?.full_name as string) || user.email?.split('@')[0] || '';
      setName(savedName);
    }
    try {
      const m = localStorage.getItem('aria_model');
      if (m) setDefaultModel(m);
    } catch {}
  }, [user]);

  const saveName = async () => {
    if (!name.trim()) return;
    setSavingName(true);
    const { error } = await supabase.auth.updateUser({ data: { full_name: name.trim() } });
    if (error) toast.error(error.message);
    else toast.success('Name updated!');
    setSavingName(false);
  };

  const savePassword = async () => {
    if (!newPassword || newPassword.length < 6) { toast.error('Password must be at least 6 characters'); return; }
    setSavingPw(true);
    const { error } = await supabase.auth.updateUser({ password: newPassword });
    if (error) toast.error(error.message);
    else { toast.success('Password updated!'); setNewPassword(''); setCurrentPassword(''); }
    setSavingPw(false);
  };

  const saveModel = (key: string) => {
    setDefaultModel(key);
    try { localStorage.setItem('aria_model', key); } catch {}
    toast.success('Default model saved');
  };

  const deleteAccount = async () => {
    toast.error('Account deletion requires admin access. Contact khansaheer424@gmail.com');
    setDeleteConfirm(false);
  };

  const clearLocalData = () => {
    try {
      const keys = Object.keys(localStorage).filter(k => k.startsWith('aria_'));
      keys.forEach(k => localStorage.removeItem(k));
      toast.success('Local data cleared');
    } catch { toast.error('Failed to clear data'); }
  };

  return (
    <div className="min-h-screen flex w-full bg-[var(--aria-bg)]">
      <SidebarNavigation isOpen={isSidebarOpen} onClose={() => setSidebarOpen(false)} user={user} displayName={displayName} onSignOut={async () => { await signOut(); toast.success('Signed out'); }} />

      <div className="flex-1 flex flex-col min-h-screen">
        {/* Header */}
        <div className="flex items-center gap-3 px-6 lg:px-10 py-4 border-b border-black/5 sticky top-0 bg-[var(--aria-bg)] z-10">
          <button onClick={() => router.push('/')} className="p-2 text-slate-500 hover:text-slate-800 rounded-xl transition-colors">
            <ArrowLeft size={20} strokeWidth={1.5} />
          </button>
          <div className="flex items-center gap-2">
            <Settings size={20} className="text-slate-600" strokeWidth={1.5} />
            <h1 className="font-bold text-slate-900 text-lg">Settings</h1>
          </div>
          <button onClick={() => setSidebarOpen(true)} className="lg:hidden ml-auto p-2 text-slate-500 rounded-xl">
            <Menu size={20} strokeWidth={1.5} />
          </button>
        </div>

        <div className="flex-1 px-6 lg:px-10 py-8 max-w-2xl w-full mx-auto space-y-5">

          {/* Profile */}
          <Section title="Profile">
            {user ? (
              <div className="space-y-4">
                <div>
                  <label className="text-[12px] text-slate-400 font-medium mb-1.5 block">Display Name</label>
                  <div className="flex gap-3">
                    <input
                      value={name}
                      onChange={e => setName(e.target.value)}
                      className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-[14px] text-slate-800 focus:outline-none focus:border-slate-400"
                      placeholder="Your name"
                    />
                    <button onClick={saveName} disabled={savingName}
                      className="px-4 py-2.5 bg-slate-900 text-white rounded-xl text-[13px] font-medium hover:bg-slate-700 disabled:opacity-50 transition-colors"
                    >
                      {savingName ? '...' : 'Save'}
                    </button>
                  </div>
                </div>
                <div>
                  <label className="text-[12px] text-slate-400 font-medium mb-1.5 block">Email</label>
                  <input
                    value={user.email || ''}
                    readOnly
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-[14px] text-slate-400 cursor-not-allowed"
                  />
                </div>
              </div>
            ) : (
              <div className="text-center py-4">
                <p className="text-slate-500 text-sm mb-3">Sign in to manage your profile</p>
                <button onClick={() => router.push('/auth')} className="btn-dark px-5 py-2.5 rounded-full text-sm">Sign In</button>
              </div>
            )}
          </Section>

          {/* Password */}
          {user && (
            <Section title="Change Password">
              <div className="space-y-4">
                <div>
                  <label className="text-[12px] text-slate-400 font-medium mb-1.5 block">New Password</label>
                  <div className="relative">
                    <input
                      type={showPw ? 'text' : 'password'}
                      value={newPassword}
                      onChange={e => setNewPassword(e.target.value)}
                      placeholder="Min. 6 characters"
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-[14px] text-slate-800 focus:outline-none focus:border-slate-400 pr-12"
                    />
                    <button onClick={() => setShowPw(s => !s)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                      {showPw ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>
                <button onClick={savePassword} disabled={savingPw || !newPassword}
                  className="w-full py-2.5 bg-slate-900 text-white rounded-xl text-[13px] font-medium hover:bg-slate-700 disabled:opacity-40 transition-colors"
                >
                  {savingPw ? 'Updating...' : 'Update Password'}
                </button>
              </div>
            </Section>
          )}

          {/* Default Model */}
          <Section title="Default AI Model">
            <div className="space-y-2">
              {MODELS.map(m => (
                <button
                  key={m.key}
                  onClick={() => saveModel(m.key)}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl border transition-all text-left
                    ${defaultModel === m.key ? 'border-slate-900 bg-slate-50' : 'border-transparent hover:bg-slate-50'}`}
                >
                  <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center shrink-0 ${defaultModel === m.key ? 'border-slate-900 bg-slate-900' : 'border-slate-300'}`}>
                    {defaultModel === m.key && <Check size={9} className="text-white" strokeWidth={3} />}
                  </div>
                  <div>
                    <p className="text-[13px] font-medium text-slate-800">{m.label}</p>
                    <p className="text-[11px] text-slate-400">{m.desc}</p>
                  </div>
                </button>
              ))}
            </div>
          </Section>

          {/* Data & Privacy */}
          <Section title="Data & Privacy">
            <div className="space-y-3">
              <div className="flex items-center justify-between py-2">
                <div>
                  <p className="text-[13px] font-medium text-slate-800">Clear local data</p>
                  <p className="text-[11px] text-slate-400">Remove all locally cached chats and preferences</p>
                </div>
                <button onClick={clearLocalData} className="px-4 py-2 border border-slate-200 text-slate-600 rounded-xl text-[12px] font-medium hover:bg-slate-50 transition-colors">
                  Clear
                </button>
              </div>

              {user && (
                <div className="flex items-center justify-between py-2 border-t border-black/5">
                  <div>
                    <p className="text-[13px] font-medium text-red-600">Delete account</p>
                    <p className="text-[11px] text-slate-400">Permanently remove your account and all data</p>
                  </div>
                  <button onClick={() => setDeleteConfirm(true)} className="px-4 py-2 border border-red-200 text-red-500 rounded-xl text-[12px] font-medium hover:bg-red-50 transition-colors">
                    Delete
                  </button>
                </div>
              )}
            </div>
          </Section>
        </div>
      </div>

      {/* Delete confirm modal */}
      <AnimatePresence>
        {deleteConfirm && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-center justify-center px-4"
            onClick={() => setDeleteConfirm(false)}
          >
            <motion.div initial={{ scale: 0.95 }} animate={{ scale: 1 }} exit={{ scale: 0.95 }}
              onClick={e => e.stopPropagation()}
              className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-xl"
            >
              <h3 className="font-bold text-slate-900 mb-2">Delete account?</h3>
              <p className="text-sm text-slate-500 mb-5">This cannot be undone. All your chats and data will be permanently deleted.</p>
              <div className="flex gap-3">
                <button onClick={() => setDeleteConfirm(false)} className="flex-1 py-2.5 border border-slate-200 rounded-xl text-[13px] text-slate-600 hover:bg-slate-50">Cancel</button>
                <button onClick={deleteAccount} className="flex-1 py-2.5 bg-red-500 text-white rounded-xl text-[13px] font-medium hover:bg-red-600">Delete</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Send, Mic, MicOff } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import { createClient } from '@/utils/supabase/client';
import toast from 'react-hot-toast';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

export default function VoicePage() {
  const router = useRouter();
  const { user } = useAuth();
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [response, setResponse] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const recognitionRef = useRef<any>(null);
  const supabase = createClient();

  const sendVoiceMessage = useCallback(async (text: string) => {
    if (!text.trim()) return;
    setIsProcessing(true);
    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: [{ role: 'user', content: text }] }),
      });
      const data = await res.json();
      setResponse(data.content);
    } catch {
      toast.error('Failed to get AI response');
    } finally {
      setIsProcessing(false);
    }
  }, []);

  const toggleListening = useCallback(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      toast.error('Voice not supported in this browser');
      return;
    }

    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = false;
    recognition.interimResults = false;
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsListening(true);
    recognition.onresult = (event: any) => {
      const text = event.results[0][0].transcript;
      setTranscript(text);
      setIsListening(false);
      sendVoiceMessage(text);
    };
    recognition.onerror = () => {
      setIsListening(false);
      toast.error('Voice error ΓÇö try again');
    };
    recognition.onend = () => setIsListening(false);
    recognition.start();
    recognitionRef.current = recognition;
  }, [isListening, sendVoiceMessage]);

  useEffect(() => {
    const timer = setTimeout(toggleListening, 600);
    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const saveAndGoToChat = async () => {
    if (!transcript) return;
    const title = transcript.slice(0, 50);

    if (!user) {
      const localId = crypto.randomUUID();
      const existing = JSON.parse(localStorage.getItem('aria_local_chats') || '[]');
      localStorage.setItem(
        'aria_local_chats',
        JSON.stringify([{ id: localId, title, created_at: new Date().toISOString() }, ...existing].slice(0, 15))
      );
      const firstPair = [
        { id: crypto.randomUUID(), role: 'user', content: transcript, created_at: new Date().toISOString() },
        ...(response ? [{ id: crypto.randomUUID(), role: 'assistant', content: response, created_at: new Date().toISOString() }] : []),
      ];
      localStorage.setItem(`aria_chat_${localId}`, JSON.stringify(firstPair));
      router.push(`/chat/${localId}`);
      return;
    }

    const { data } = await supabase.from('chats').insert({ user_id: user.id, title }).select('id').single();
    if (data) {
      await supabase.from('messages').insert({ chat_id: data.id, role: 'user', content: transcript });
      if (response) {
        await supabase.from('messages').insert({ chat_id: data.id, role: 'assistant', content: response });
      }
      router.push(`/chat/${data.id}`);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between px-6 py-10 bg-[var(--aria-bg)]">

      {/* Header */}
      <div className="w-full max-w-md flex items-center justify-between">
        <button
          onClick={() => { recognitionRef.current?.stop(); router.push('/'); }}
          className="p-2 text-slate-500 hover:text-slate-800 rounded-xl transition-colors"
        >
          <ArrowLeft size={22} strokeWidth={1.5} />
        </button>
        <span className="font-semibold text-slate-800 text-[15px]">Voice Mode</span>
        <div className="w-10" />
      </div>

      {/* Orb area */}
      <div className="flex flex-col items-center gap-8 flex-1 justify-center w-full max-w-md">

        {/* Animated mic orb */}
        <motion.button
          onClick={toggleListening}
          className="relative w-28 h-28 rounded-full flex items-center justify-center"
          style={{ background: isListening ? 'var(--aria-pastel-purple)' : '#e8e4db' }}
          animate={isListening ? { scale: [1, 1.06, 1] } : { scale: 1 }}
          transition={{ duration: 1.4, repeat: isListening ? Infinity : 0 }}
        >
          {isListening
            ? <MicOff size={36} className="text-white" />
            : <Mic size={36} className="text-slate-500" />
          }
          {isListening && (
            <motion.div
              className="absolute inset-0 rounded-full"
              style={{ border: '2px solid var(--aria-pastel-purple)' }}
              animate={{ scale: [1, 1.4], opacity: [0.6, 0] }}
              transition={{ duration: 1.4, repeat: Infinity }}
            />
          )}
        </motion.button>

        <p className="text-slate-500 text-sm font-medium">
          {isListening ? '≡ƒÄñ Listening...' : isProcessing ? 'ΓÅ│ Thinking...' : 'Tap to speak'}
        </p>

        {/* Transcript card */}
        <AnimatePresence>
          {transcript && (
            <motion.div
              key="transcript"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="w-full bg-white rounded-2xl px-5 py-4 shadow-sm border border-black/5"
            >
              <p className="text-xs text-slate-400 mb-1 font-medium uppercase tracking-wider">You said</p>
              <p className="text-slate-800 text-sm leading-relaxed">"{transcript}"</p>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Loading dots */}
        <AnimatePresence>
          {isProcessing && (
            <motion.div
              key="processing"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="w-full bg-white rounded-2xl px-5 py-4 shadow-sm border border-black/5"
            >
              <p className="text-xs text-slate-400 mb-2 font-medium uppercase tracking-wider">Aria</p>
              <div className="flex gap-1.5">
                <div className="w-2 h-2 bg-slate-300 rounded-full typing-dot" />
                <div className="w-2 h-2 bg-slate-300 rounded-full typing-dot" />
                <div className="w-2 h-2 bg-slate-300 rounded-full typing-dot" />
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* AI response */}
        <AnimatePresence>
          {response && !isProcessing && (
            <motion.div
              key="response"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="w-full bg-white rounded-2xl px-5 py-4 shadow-sm border border-black/5"
            >
              <p className="text-xs text-slate-400 mb-1 font-medium uppercase tracking-wider">Aria</p>
              <p className="text-slate-800 text-sm leading-relaxed">{response}</p>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Bottom controls */}
      <div className="w-full max-w-md flex flex-col items-center gap-3">
        {transcript && !isProcessing && (
          <button
            onClick={saveAndGoToChat}
            className="w-full btn-dark py-4 rounded-2xl flex items-center justify-center gap-2 text-white font-medium"
          >
            <Send size={16} />
            Continue in Chat
          </button>
        )}
        <button
          onClick={() => { setTranscript(''); setResponse(''); }}
          className="text-slate-400 text-sm hover:text-slate-600 transition-colors"
        >
          Clear &amp; Start Over
        </button>
      </div>
    </div>
  );
}

'use client';

import { motion } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { CodeBlock } from './CodeBlock';

interface ChatBubbleProps {
  role: 'user' | 'assistant';
  content: string;
  model?: string;
  timestamp?: string;
}

export function ChatBubble({ role, content, model, timestamp }: ChatBubbleProps) {
  const isUser = role === 'user';

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.18 }}
      className={`flex gap-3 mb-6 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}
    >
      {/* Avatar */}
      {!isUser && (
        <div className="w-7 h-7 rounded-full bg-[var(--aria-pastel-purple)] flex items-center justify-center text-[11px] font-bold text-slate-700 shrink-0 mt-0.5">
          A
        </div>
      )}

      <div className={`flex flex-col gap-1 ${isUser ? 'items-end' : 'items-start'} max-w-[82%]`}>
        <div className={isUser ? 'bubble-user px-4 py-2.5' : 'bubble-ai px-4 py-3 w-full'}>
          {isUser ? (
            // User: plain text
            <p className="text-[15px] text-slate-900 leading-relaxed whitespace-pre-wrap break-words">{content}</p>
          ) : (
            // AI: rich markdown
            <div className="ai-prose text-[15px] leading-relaxed text-slate-900">
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                components={{
                  // Headings
                  h1: ({ children }) => <h1 className="text-xl font-bold mt-4 mb-2 first:mt-0">{children}</h1>,
                  h2: ({ children }) => <h2 className="text-lg font-semibold mt-3 mb-1.5 first:mt-0">{children}</h2>,
                  h3: ({ children }) => <h3 className="text-base font-semibold mt-2 mb-1 first:mt-0">{children}</h3>,
                  // Paragraphs
                  p: ({ children }) => <p className="mb-2 last:mb-0 leading-relaxed">{children}</p>,
                  // Lists
                  ul: ({ children }) => <ul className="list-disc list-outside ml-4 mb-2 space-y-1">{children}</ul>,
                  ol: ({ children }) => <ol className="list-decimal list-outside ml-4 mb-2 space-y-1">{children}</ol>,
                  li: ({ children }) => <li className="leading-relaxed">{children}</li>,
                  // Inline code and block code
                  code: ({ children, className }) => {
                    const match = /language-(\w+)/.exec(className || '');
                    const isInline = !match;

                    if (!isInline) {
                      return (
                        <CodeBlock 
                          language={match[1]} 
                          value={String(children).replace(/\n$/, '')} 
                        />
                      );
                    }

                    return (
                      <code className="bg-black/5 text-slate-800 rounded-md px-1.5 py-0.5 text-[13px] font-mono font-medium">
                        {children}
                      </code>
                    );
                  },
                  // Code block wrapper
                  pre: ({ children }) => <pre className="my-2 overflow-x-auto">{children}</pre>,
                  // Blockquote
                  blockquote: ({ children }) => (
                    <blockquote className="border-l-4 border-slate-200 pl-4 py-1 my-4 italic text-slate-500 bg-slate-50/50 rounded-r-lg">
                      {children}
                    </blockquote>
                  ),
                  // Links
                  a: ({ href, children }) => (
                    <a href={href} target="_blank" rel="noopener noreferrer" className="text-blue-600 underline underline-offset-2 hover:text-blue-800">
                      {children}
                    </a>
                  ),
                  // Strong / em
                  strong: ({ children }) => <strong className="font-semibold text-slate-900">{children}</strong>,
                  em: ({ children }) => <em className="italic">{children}</em>,
                  // Horizontal rule
                  hr: () => <hr className="my-3 border-slate-200" />,
                  // Table
                  table: ({ children }) => (
                    <div className="overflow-hidden my-4 border border-slate-200 rounded-xl shadow-sm">
                      <table className="min-w-full text-[13.5px] border-collapse">{children}</table>
                    </div>
                  ),
                  thead: ({ children }) => <thead className="bg-slate-50 border-b border-slate-200 font-semibold">{children}</thead>,
                  th: ({ children }) => <th className="px-4 py-3 text-left font-bold text-slate-700 border-r border-slate-200 last:border-0">{children}</th>,
                  td: ({ children }) => <td className="px-4 py-3 border-b border-r border-slate-100 last:border-r-0 last:border-b-0 hover:bg-slate-50/50 transition-colors">{children}</td>,
                  tr: ({ children }) => <tr className="last:border-0">{children}</tr>,
                  // Images ΓÇö renders DeepAI generated images
                  img: ({ src, alt }) => {
                    const imgSrc = typeof src === 'string' ? src : undefined;
                    return (
                      <div className="my-3 flex flex-col gap-2">
                        <img
                          src={imgSrc}
                          alt={alt || 'Generated image'}
                          className="rounded-2xl max-w-full shadow-md border border-black/5 w-full"
                          style={{ maxHeight: '480px', objectFit: 'contain' }}
                        />
                        {imgSrc && (
                          <a
                            href={imgSrc}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="self-start text-[12px] font-medium text-slate-500 hover:text-slate-800 transition-colors"
                          >
                            Γåô Open full image
                          </a>
                        )}
                      </div>
                    );
                  },
                }}
              >
                {content}
              </ReactMarkdown>
            </div>
          )}
        </div>

        {/* Meta row */}
        <div className={`flex items-center gap-2 px-1 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>
          {timestamp && (
            <span className="text-[11px] text-slate-400">
              {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          )}
          {!isUser && model && (
            <span className="text-[10px] font-semibold text-slate-400 uppercase tracking-wider">{model}</span>
          )}
        </div>
      </div>
    </motion.div>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ThumbsUp, ThumbsDown, Sparkles } from 'lucide-react';

interface RatingButtonsProps {
  memoryIds?: string[];
  messageId?: string;
  onRated?: (rating: 1 | -1) => void;
}

export function RatingButtons({ memoryIds, messageId, onRated }: RatingButtonsProps) {
  const [rated, setRated] = useState<1 | -1 | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMemoryBadge, setShowMemoryBadge] = useState(
    () => memoryIds && memoryIds.length > 0
  );

  const handleRate = async (rating: 1 | -1) => {
    if (rated || loading) return;
    setLoading(true);

    try {
      if (memoryIds && memoryIds.length > 0) {
        // Rate all associated memories
        await Promise.all(
          memoryIds.map(id =>
            fetch('/api/rag/rate', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ memoryId: id, rating }),
            })
          )
        );
      }

      setRated(rating);
      onRated?.(rating);
    } catch (err) {
      console.error('[RatingButtons] Error rating memory:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center gap-2 mt-2">
      {/* Memory badge ΓÇö shows when RAG context was used */}
      <AnimatePresence>
        {showMemoryBadge && memoryIds && memoryIds.length > 0 && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8 }}
            className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-violet-50 border border-violet-100 text-violet-600"
            title={`${memoryIds.length} memory chunk(s) used to generate this response`}
          >
            <Sparkles size={10} strokeWidth={2} />
            <span className="text-[10px] font-semibold">
              {memoryIds.length} memor{memoryIds.length === 1 ? 'y' : 'ies'} used
            </span>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Rating buttons */}
      <div className="flex items-center gap-1">
        <AnimatePresence mode="wait">
          {rated ? (
            <motion.span
              key="rated"
              initial={{ opacity: 0, y: 4 }}
              animate={{ opacity: 1, y: 0 }}
              className={`text-[11px] font-medium px-2 py-0.5 rounded-full ${
                rated === 1
                  ? 'bg-green-50 text-green-600 border border-green-100'
                  : 'bg-red-50 text-red-500 border border-red-100'
              }`}
            >
              {rated === 1 ? 'Thanks! Memory updated Γ£ô' : 'Got it, memory downgraded'}
            </motion.span>
          ) : (
            <motion.div
              key="buttons"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="flex items-center gap-1"
            >
              <button
                id={`rate-up-${messageId}`}
                onClick={() => handleRate(1)}
                disabled={loading}
                title="Good response ΓÇö boost related memories"
                className="p-1.5 rounded-lg text-slate-400 hover:text-green-500 hover:bg-green-50 transition-colors disabled:opacity-40"
              >
                <ThumbsUp size={13} strokeWidth={1.8} />
              </button>
              <button
                id={`rate-down-${messageId}`}
                onClick={() => handleRate(-1)}
                disabled={loading}
                title="Bad response ΓÇö downgrade related memories"
                className="p-1.5 rounded-lg text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors disabled:opacity-40"
              >
                <ThumbsDown size={13} strokeWidth={1.8} />
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

